// MARK: - File: KeyManager.swift

import Foundation

enum KeyManager {
    
    enum KeyError: Error, LocalizedStringErrorConvertible {
        case plistNotFound
        case keyNotFound(String)
        
        var localizedDescription: String {
            switch self {
            case .plistNotFound:
                return "Keys.plist not found in bundle. See README for setup."
            case .keyNotFound(let key):
                return "Key '\(key)' not found in Keys.plist"
            }
        }
    }
    
    private static var cachedKeys: [String: String]?
    
    private static func loadKeys() throws -> [String: String] {
        if let cached = cachedKeys {
            return cached
        }
        
        guard let path = Bundle.main.path(forResource: "Keys", ofType: "plist"),
              let dict = NSDictionary(contentsOfFile: path) as? [String: String] else {
            throw KeyError.plistNotFound
        }
        
        cachedKeys = dict
        return dict
    }
    
    static var googleMapsAPIKey: String {
        get throws {
            let keys = try loadKeys()
            guard let key = keys["GOOGLE_MAPS_API_KEY"], !key.isEmpty, key != "YOUR_KEY_HERE" else {
                throw KeyError.keyNotFound("GOOGLE_MAPS_API_KEY")
            }
            return key
        }
    }
    
    static var stripePublishableKey: String {
        get throws {
            let keys = try loadKeys()
            guard let key = keys["STRIPE_PUBLISHABLE_KEY"], !key.isEmpty, key != "YOUR_KEY_HERE" else {
                throw KeyError.keyNotFound("STRIPE_PUBLISHABLE_KEY")
            }
            return key
        }
    }
}

protocol LocalizedStringErrorConvertible {
    var localizedDescription: String { get }
}

