// MARK: - File: Models.swift

import Foundation
import CoreLocation

struct ServiceLocation: Identifiable {
    let id: String
    let name: String
    let description: String
    let coordinate: CLLocationCoordinate2D
    let rating: Double
    let pricePerHour: Double
    let category: ServiceCategory
    let imageURL: String?
    let isAvailable: Bool
    
    var formattedPrice: String {
        return String(format: "$%.2f/hr", pricePerHour)
    }
}

enum ServiceCategory: String, CaseIterable {
    case workspace = "Workspace"
    case parking = "Parking"
    case storage = "Storage"
    case studio = "Studio"
    
    var icon: String {
        switch self {
        case .workspace: return "desktopcomputer"
        case .parking: return "car.fill"
        case .storage: return "shippingbox.fill"
        case .studio: return "music.note.house.fill"
        }
    }
    
    var color: UIColor {
        switch self {
        case .workspace: return .systemBlue
        case .parking: return .systemGreen
        case .storage: return .systemOrange
        case .studio: return .systemPurple
        }
    }
}

struct Booking: Identifiable {
    let id: String
    let location: ServiceLocation
    let startDate: Date
    let endDate: Date
    let totalPrice: Double
    let status: BookingStatus
    
    var formattedTotal: String {
        return String(format: "$%.2f", totalPrice)
    }
}

enum BookingStatus: String {
    case confirmed = "Confirmed"
    case pending = "Pending"
    case completed = "Completed"
    case cancelled = "Cancelled"
    
    var color: UIColor {
        switch self {
        case .confirmed: return .systemGreen
        case .pending: return .systemOrange
        case .completed: return .systemBlue
        case .cancelled: return .systemRed
        }
    }
}

